import React, { useEffect, useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { toast } from 'sonner';
import { ArrowLeft, CheckCircle2, MapPin, Package, Truck, CreditCard, TicketPercent, ChevronRight } from 'lucide-react';
import LiquidLoader from '../../components/LiquidLoader';

export default function Checkout() {
  const [cart, setCart] = useState(null);
  const [loading, setLoading] = useState(true);
  const [placingOrder, setPlacingOrder] = useState(false);
  const [orderSuccess, setOrderSuccess] = useState(null);
  const [shippingMethod, setShippingMethod] = useState('reguler');
  const [paymentMethod, setPaymentMethod] = useState('bank_transfer');
  
  const [formData, setFormData] = useState({
    name: 'Jane Doe',
    phone: '081234567890',
    address: 'Jl. Jend. Sudirman No. 1, Senayan',
    city: 'Jakarta Pusat',
    postalCode: '10270',
  });
  
  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  useEffect(() => {
    if (!token) {
      navigate('/login');
      return;
    }
    fetchCart();
  }, [token, navigate]);

  const fetchCart = async () => {
    try {
      await new Promise(r => setTimeout(r, 600));
      const data = {
        items: [{
          product: { name: { id: "Pashmina Premium", en: "Premium Pashmina" }, price: "Rp 125.000", image: process.env.PUBLIC_URL + "/assets/koleksi/pashmina.webp" },
          variant_id: "Standard",
          quantity: 1,
          price_at_addition: 125000,
          subtotal: 125000
        }],
        total_amount: 125000
      };
      if (!data.items || data.items.length === 0) {
        toast.error('Keranjang kosong');
        navigate('/cart');
      }
      setCart(data);
    } catch (err) {
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleCheckout = async () => {
    setPlacingOrder(true);
    try {
      // Simulate API call for marketplace dummy checkout
      await new Promise(r => setTimeout(r, 1500));
      
      const whatsappMessage = `Halo DES! Saya ingin memesan:\n\n` + 
        `- Pashmina Premium (1x) - Rp 125.000\n` +
        `\nTotal Belanja: Rp 125.000 (belum ongkir)\n\n` +
        `Detail Pengiriman:\n` +
        `Nama: ${formData.name}\n` +
        `Alamat: ${formData.address}\n` +
        `No HP: ${formData.phone}\n`;

      const waUrl = `https://wa.me/6285117689792?text=${encodeURIComponent(whatsappMessage)}`;
      window.open(waUrl, '_blank');

      setOrderSuccess(`ORD-${Math.floor(Math.random() * 1000000)}`);
      toast.success('Pesanan berhasil dibuat!');
      setPlacingOrder(false);
      
    } catch (err) {
      toast.error(err.message);
      setPlacingOrder(false);
    }
  };

  if (loading) return <LiquidLoader fullScreen />;

  if (orderSuccess) {
    return (
      <div className="min-h-screen bg-secondary/20 pt-32 pb-16 flex items-center justify-center -mt-20">
        <div className="max-w-md w-full text-center space-y-6 bg-card p-10 rounded-2xl shadow-sm border border-border/50">
          <CheckCircle2 className="w-20 h-20 text-green-500 mx-auto" />
          <h2 className="text-2xl font-bold text-foreground">Pembayaran Berhasil</h2>
          <p className="text-muted-foreground text-sm">
            Terima kasih telah berbelanja di DES. Pesanan Anda sedang diproses.
          </p>
          <div className="bg-secondary/30 p-4 rounded-xl mb-4">
             <span className="text-xs text-muted-foreground uppercase tracking-widest block mb-1">Total Pembayaran</span>
             <span className="text-2xl font-bold text-primary">Rp {(calculateTotal()).toLocaleString('id-ID')}</span>
             <div className="mt-4 text-xs font-mono text-foreground">Order ID: #{orderSuccess.split('-')[0]}</div>
          </div>
          <div className="pt-2 space-y-3">
            <Link to="/dashboard" className="w-full flex justify-center py-3.5 px-4 rounded-full text-sm font-medium text-background bg-foreground hover:bg-foreground/90 transition-colors shadow-md">
              Lihat Pesanan Saya
            </Link>
            <Link to="/collection" className="w-full flex justify-center py-3.5 px-4 text-sm font-medium text-foreground border border-border rounded-full hover:bg-secondary/50 transition-colors">
              Kembali Belanja
            </Link>
          </div>
        </div>
      </div>
    );
  }

  const subtotal = cart?.items?.reduce((sum, item) => sum + (item.price_at_addition * item.quantity), 0) || 0;
  
  function getShippingCost() {
    switch (shippingMethod) {
      case 'reguler': return 15000;
      case 'hemat': return 10000;
      case 'kargo': return 35000;
      default: return 15000;
    }
  }

  function calculateTotal() {
    return subtotal + getShippingCost();
  }

  return (
    <div className="min-h-screen bg-[#F5F5F5] pt-24 pb-32">
      <div className="container mx-auto px-4 max-w-4xl">
        <div className="flex items-center mb-6">
          <button onClick={() => navigate('/cart')} className="flex items-center text-sm font-medium text-muted-foreground hover:text-foreground transition-colors">
            <ArrowLeft className="w-5 h-5 mr-2" /> Checkout
          </button>
        </div>
        
        <div className="space-y-4">
          
          {/* Alamat Pengiriman */}
          <section className="bg-card rounded-xl shadow-sm overflow-hidden">
            <div className="h-1 w-full bg-gradient-to-r from-red-500 via-blue-500 to-red-500 opacity-80" style={{ backgroundSize: '116px 3px' }}></div>
            <div className="p-6">
              <div className="flex items-center text-primary mb-3">
                <MapPin className="w-5 h-5 mr-2" />
                <h3 className="font-semibold text-foreground">Alamat Pengiriman</h3>
              </div>
              <div className="ml-7 text-sm">
                <p className="font-bold text-foreground mb-1">{formData.name} <span className="font-normal text-muted-foreground">({formData.phone})</span></p>
                <p className="text-muted-foreground">{formData.address}</p>
                <p className="text-muted-foreground">{formData.city}, {formData.postalCode}</p>
              </div>
            </div>
          </section>

          {/* Produk Dipesan */}
          <section className="bg-card rounded-xl shadow-sm p-6">
             <div className="flex items-center mb-4">
                <Package className="w-5 h-5 mr-2 text-primary" />
                <h3 className="font-semibold text-foreground">Produk Dipesan</h3>
             </div>
             <div className="space-y-4">
               {cart?.items?.map((item, idx) => (
                 <div key={idx} className="flex gap-4 p-4 border border-border/50 rounded-lg">
                    <div className="w-16 h-16 bg-muted rounded-md shrink-0">
                      <img src={process.env.PUBLIC_URL + "/assets/inspirasi/Flyer A1.jpg"} alt="product" className="w-full h-full object-cover rounded-md" />
                    </div>
                    <div className="flex-1">
                      <h4 className="font-medium text-foreground line-clamp-1">{item.product_id}</h4>
                      <p className="text-xs text-muted-foreground mt-1">Variasi: Standard</p>
                      <div className="flex justify-between items-center mt-2">
                        <span className="text-sm font-medium">Rp {item.price_at_addition.toLocaleString('id-ID')}</span>
                        <span className="text-xs text-muted-foreground">x{item.quantity}</span>
                      </div>
                    </div>
                 </div>
               ))}
             </div>
             <div className="mt-4 flex items-center text-sm border-t border-border/50 pt-4">
               <span className="text-foreground w-32">Pesan:</span>
               <input type="text" placeholder="(Opsional) Tinggalkan pesan ke penjual" className="flex-1 outline-none text-muted-foreground placeholder:text-muted-foreground/50 bg-transparent" />
             </div>
          </section>

          {/* Opsi Pengiriman */}
          <section className="bg-card rounded-xl shadow-sm p-6">
            <div className="flex items-center mb-4 text-primary">
              <Truck className="w-5 h-5 mr-2" />
              <h3 className="font-semibold text-foreground">Opsi Pengiriman</h3>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
               <label className={`border rounded-lg p-4 cursor-pointer transition-all ${shippingMethod === 'hemat' ? 'border-primary bg-primary/5 ring-1 ring-primary' : 'border-border hover:border-foreground/30'}`}>
                 <input type="radio" name="shipping" value="hemat" checked={shippingMethod === 'hemat'} onChange={(e) => setShippingMethod(e.target.value)} className="hidden" />
                 <div className="flex justify-between mb-1">
                   <span className="font-medium text-sm">Hemat</span>
                   <span className="font-bold text-sm">Rp 10.000</span>
                 </div>
                 <p className="text-xs text-muted-foreground">Estimasi diterima 3-5 hr</p>
               </label>
               <label className={`border rounded-lg p-4 cursor-pointer transition-all ${shippingMethod === 'reguler' ? 'border-primary bg-primary/5 ring-1 ring-primary' : 'border-border hover:border-foreground/30'}`}>
                 <input type="radio" name="shipping" value="reguler" checked={shippingMethod === 'reguler'} onChange={(e) => setShippingMethod(e.target.value)} className="hidden" />
                 <div className="flex justify-between mb-1">
                   <span className="font-medium text-sm">Reguler</span>
                   <span className="font-bold text-sm">Rp 15.000</span>
                 </div>
                 <p className="text-xs text-muted-foreground">Estimasi diterima 2-3 hr</p>
               </label>
               <label className={`border rounded-lg p-4 cursor-pointer transition-all ${shippingMethod === 'kargo' ? 'border-primary bg-primary/5 ring-1 ring-primary' : 'border-border hover:border-foreground/30'}`}>
                 <input type="radio" name="shipping" value="kargo" checked={shippingMethod === 'kargo'} onChange={(e) => setShippingMethod(e.target.value)} className="hidden" />
                 <div className="flex justify-between mb-1">
                   <span className="font-medium text-sm">Kargo</span>
                   <span className="font-bold text-sm">Rp 35.000</span>
                 </div>
                 <p className="text-xs text-muted-foreground">Estimasi diterima 5-7 hr</p>
               </label>
            </div>
          </section>

          {/* Shopee Voucher (Dummy) */}
          <section className="bg-card rounded-xl shadow-sm p-4 flex items-center justify-between cursor-pointer hover:bg-secondary/20 transition-colors">
             <div className="flex items-center text-foreground">
               <TicketPercent className="w-5 h-5 mr-3 text-red-500" />
               <span className="text-sm font-medium">Voucher Toko</span>
             </div>
             <div className="flex items-center text-sm text-muted-foreground">
               Pilih Voucher <ChevronRight className="w-4 h-4 ml-1" />
             </div>
          </section>

          {/* Metode Pembayaran */}
          <section className="bg-card rounded-xl shadow-sm p-6 mb-24">
            <div className="flex items-center mb-4 text-primary">
              <CreditCard className="w-5 h-5 mr-2" />
              <h3 className="font-semibold text-foreground">Metode Pembayaran</h3>
            </div>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
               {['Transfer Bank', 'COD (Bayar di Tempat)', 'Virtual Account', 'E-Wallet'].map((m) => {
                 const id = m.toLowerCase().replace(/ /g, '_');
                 return (
                   <label key={id} className={`border rounded-lg p-3 cursor-pointer text-center transition-all ${paymentMethod === id ? 'border-primary bg-primary/5 text-primary font-medium' : 'border-border text-foreground hover:border-foreground/30'}`}>
                     <input type="radio" name="payment" value={id} checked={paymentMethod === id} onChange={(e) => setPaymentMethod(e.target.value)} className="hidden" />
                     <span className="text-xs">{m}</span>
                   </label>
                 );
               })}
            </div>
          </section>
        </div>
      </div>

      {/* Shopee-style Sticky Footer Checkout Baru */}
      <div className="fixed bottom-0 left-0 right-0 bg-card border-t border-border shadow-[0_-4px_10px_rgba(0,0,0,0.05)] z-50">
        <div className="container mx-auto px-4 max-w-4xl h-20 flex items-center justify-between lg:justify-end lg:gap-8 gap-4">
           <div className="text-right flex-1 lg:flex-none">
             <p className="text-xs text-muted-foreground">Total Pembayaran</p>
             <p className="text-2xl font-bold text-primary">Rp {calculateTotal().toLocaleString('id-ID')}</p>
           </div>
           <button
             onClick={handleCheckout}
             disabled={placingOrder}
             className="h-12 px-8 bg-primary hover:bg-primary/90 text-background font-medium rounded-lg transition-colors disabled:opacity-70 disabled:cursor-not-allowed shadow-md w-1/2 lg:w-48"
           >
             {placingOrder ? 'Memproses...' : 'Buat Pesanan'}
           </button>
        </div>
      </div>
    </div>
  );
}
